import { type GetCounter } from 'wasp/server/operations'

export const getCounter: GetCounter<void, any> = async (args, context) => {
  const counter = await context.entities.Counter.findFirst()
  if (!counter) {
    return context.entities.Counter.create({
      data: { count: 0 },
    })
  }
  return counter
}

