import { type Increment, type Decrement } from 'wasp/server/operations'

export const increment: Increment<void, any> = async (args, context) => {
  const counter = await context.entities.Counter.findFirst()
  if (!counter) {
    return context.entities.Counter.create({
      data: { count: 1 },
    })
  }
  return context.entities.Counter.update({
    where: { id: counter.id },
    data: { count: { increment: 1 } },
  })
}

export const decrement: Decrement<void, any> = async (args, context) => {
  const counter = await context.entities.Counter.findFirst()
  if (!counter) {
    return context.entities.Counter.create({
      data: { count: -1 },
    })
  }
  return context.entities.Counter.update({
    where: { id: counter.id },
    data: { count: { decrement: 1 } },
  })
}

