import { useQuery, useAction, getCounter, increment, decrement } from 'wasp/client/operations'
import "./Main.css";

export function MainPage() {
  const { data: counter, isLoading, error } = useQuery(getCounter)
  const incrementAction = useAction(increment)
  const decrementAction = useAction(decrement)

  if (isLoading) return 'Loading...'
  if (error) return 'Error: ' + error.message

  return (
    <main className="container">
      <h2 className="title">Wasp Counter</h2>
      <div className="content">
        <p>Current count: <strong>{counter?.count ?? 0}</strong></p>
      </div>
      <div className="buttons">
        <button className="button button-filled" onClick={() => incrementAction()}>Increment</button>
        <button className="button button-outlined" onClick={() => decrementAction()}>Decrement</button>
      </div>
    </main>
  );
}

